import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { PiggyBank, Plus, AlertCircle } from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [perfil, setPerfil] = useState(null);
  const [dados, setDados] = useState({
    metaGlobal: 0,
    gastoAtual: 0,
    categorias: []
  });

  useEffect(() => {
    verificarAcessoEBuscarDados();
  }, []);

  async function verificarAcessoEBuscarDados() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfilData } = await supabase.from('profiles')
        .select('*').eq('id', user.id).single();

      const isMaster = user.email === 'gleidson.fig@gmail.com';
      if (perfilData?.tipo_usuario !== 'proprietario' && !isMaster) {
        window.location.href = '/dashboard';
        return;
      }
      setPerfil(perfilData);

      // 1. Buscar Proventos (Coluna: 'valor')
      const { data: proventos, error: errProv } = await supabase
        .from('proventos')
        .select('valor'); // AJUSTADO AQUI
      
      if (errProv) throw errProv;
      const totalProventos = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;

      // 2. Buscar Compras (Coluna: 'valor_total')
      const { data: compras, error: errComp } = await supabase
        .from('compras')
        .select('valor_total, categoria_id')
        .eq('tipo_despesa', 'Gastos Variáveis');

      if (errComp) throw errComp;
      const gastoGlobal = compras?.reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;

      // 3. Buscar Categorias e cruzar os dados
      const { data: cats } = await supabase
        .from('categorias')
        .select('*')
        .order('nome', { ascending: true });

      const categoriasProcessadas = cats.map(cat => {
        const gastoTotal = compras
          ?.filter(c => c.categoria_id === cat.id)
          .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;
        
        return {
          id: cat.id,
          nome: cat.nome,
          cor: cat.cor || '#4361ee',
          meta: cat.meta || 0, // Certifique-se que existe a coluna 'meta' em categorias
          gasto: gastoTotal
        };
      });

      const metaGlobalTotal = categoriasProcessadas.reduce((acc, cur) => acc + cur.meta, 0);

      setDados({
        metaGlobal: metaGlobalTotal > 0 ? metaGlobalTotal : totalProventos,
        gastoAtual: gastoGlobal,
        categorias: categoriasProcessadas
      });

    } catch (err) {
      console.error("Erro detalhado:", err);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const porcGlobal = dados.metaGlobal > 0 ? (dados.gastoAtual / dados.metaGlobal) * 100 : 0;

  if (loading) return <div className="loading-state">Carregando Orçamento...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div>
          <h2>Orçamento Mensal</h2>
          <p>Análise de limites e categorias</p>
        </div>
        <button className="btn-novo-orcamento" onClick={() => window.location.href='/categorias'}>
          <Plus size={20} /> Ajustar Metas
        </button>
      </header>

      <section className="meta-global-card">
        <div className="meta-info">
          <div className="meta-text">
            <span>Uso do Limite Global</span>
            <h3>
              {formatMoney(dados.gastoAtual)} 
              <small> / {formatMoney(dados.metaGlobal)}</small>
            </h3>
          </div>
          <PiggyBank size={40} color="#4361ee" />
        </div>
        
        <div className="progress-bar-container">
          <div 
            className={`progress-bar-fill ${porcGlobal > 100 ? 'over-limit' : ''}`}
            style={{ width: `${Math.min(porcGlobal, 100)}%` }}
          />
        </div>
        <div className="meta-footer">
            <span className="progress-label">{porcGlobal.toFixed(1)}% utilizado</span>
            <span className="remaining-label">
                Disponível: {formatMoney(Math.max(0, dados.metaGlobal - dados.gastoAtual))}
            </span>
        </div>
      </section>

      <div className="orcamento-grid">
        {dados.categorias.map((cat) => {
          const porc = cat.meta > 0 ? (cat.gasto / cat.meta) * 100 : 0;
          const excedeu = cat.gasto > cat.meta && cat.meta > 0;

          return (
            <div key={cat.id} className={`categoria-card ${excedeu ? 'card-excedido' : ''}`}>
              <div className="categoria-header">
                <div className="cat-info-main">
                    <div className="dot" style={{backgroundColor: cat.cor}}></div>
                    <span className="categoria-nome">{cat.nome}</span>
                </div>
                {excedeu && <AlertCircle size={18} color="#ef4444" />}
              </div>
              
              <div className="categoria-valores">
                <div className="v-group">
                    <label>Gasto</label>
                    <span className="valor-gasto">{formatMoney(cat.gasto)}</span>
                </div>
                <div className="v-group align-right">
                    <label>Meta</label>
                    <span className="valor-meta">{formatMoney(cat.meta)}</span>
                </div>
              </div>

              <div className="mini-progress-bg">
                <div 
                  className="mini-progress-fill"
                  style={{ 
                    width: `${Math.min(porc, 100)}%`,
                    backgroundColor: excedeu ? '#ef4444' : cat.cor
                  }}
                />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
